use regex::bytes::{Captures, Regex, RegexBuilder};

use crate::flags::{parse_flags, FlagSet};

pub struct AmbiguousReplacement {
    pub digits: String,
    pub trail: String,
    pub pos: usize,
    pub length: usize,
    pub replacement: String,
}

impl AmbiguousReplacement {
    pub fn render(&self) -> String {
        let mut s = String::new();
        s.push_str(&format!(
            "error: The numbered capture group `${}` in the replacement text is ambiguous.\n",
            self.digits
        ));
        s.push_str(&format!(
            "hint: Use curly braces to disambiguate it `${{{}}}{}`.\n",
            self.digits, self.trail
        ));
        s.push_str(&self.replacement);
        s.push('\n');
        for _ in 0..self.pos {
            s.push(' ');
        }
        for _ in 0..self.length {
            s.push('^');
        }
        s.push('\n');
        s
    }
}

pub fn check_ambiguous(replacement: &str) -> Result<(), AmbiguousReplacement> {
    let bytes = replacement.as_bytes();
    let n = bytes.len();
    let mut i = 0;
    while i < n {
        let b = bytes[i];
        if b == b'$' {
            if i + 1 < n && bytes[i + 1] == b'$' {
                i += 2;
                continue;
            }
            if i + 1 < n && bytes[i + 1] == b'{' {
                if let Some(p) = bytes[i + 2..].iter().position(|&c| c == b'}') {
                    i = i + 2 + p + 1;
                    continue;
                } else {
                    i += 1;
                    continue;
                }
            }
            let mut j = i + 1;
            while j < n && bytes[j].is_ascii_digit() {
                j += 1;
            }
            if j > i + 1 {
                // $NUMBER
                if j < n && is_word(bytes[j]) {
                    let mut k = j;
                    while k < n && is_word(bytes[k]) {
                        k += 1;
                    }
                    return Err(AmbiguousReplacement {
                        digits: replacement[i + 1..j].to_string(),
                        trail: replacement[j..k].to_string(),
                        pos: i + 1,
                        length: k - (i + 1),
                        replacement: replacement.to_string(),
                    });
                }
                i = j;
            } else {
                let mut j = i + 1;
                while j < n && is_word(bytes[j]) {
                    j += 1;
                }
                if j > i + 1 {
                    i = j;
                } else {
                    i += 1;
                }
            }
        } else {
            i += 1;
        }
    }
    Ok(())
}

fn is_word(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_'
}

pub fn expand(replacement: &str, caps: &Captures) -> Vec<u8> {
    let bytes = replacement.as_bytes();
    let n = bytes.len();
    let mut out = Vec::with_capacity(n);
    let mut i = 0;
    while i < n {
        let b = bytes[i];
        if b == b'\\' && i + 1 < n {
            match bytes[i + 1] {
                b'n' => {
                    out.push(b'\n');
                    i += 2;
                }
                b'r' => {
                    out.push(b'\r');
                    i += 2;
                }
                b't' => {
                    out.push(b'\t');
                    i += 2;
                }
                b'\\' => {
                    out.push(b'\\');
                    i += 2;
                }
                b'"' => {
                    out.push(b'"');
                    i += 2;
                }
                b'\'' => {
                    out.push(b'\'');
                    i += 2;
                }
                b'x' if i + 3 < n
                    && bytes[i + 2].is_ascii_hexdigit()
                    && bytes[i + 3].is_ascii_hexdigit() =>
                {
                    let hex = std::str::from_utf8(&bytes[i + 2..i + 4]).unwrap();
                    out.push(u8::from_str_radix(hex, 16).unwrap());
                    i += 4;
                }
                _ => {
                    out.push(b'\\');
                    i += 1;
                }
            }
        } else if b == b'$' {
            if i + 1 < n && bytes[i + 1] == b'$' {
                out.push(b'$');
                i += 2;
                continue;
            }
            if i + 1 < n && bytes[i + 1] == b'{' {
                if let Some(p) = bytes[i + 2..].iter().position(|&c| c == b'}') {
                    let name = &replacement[i + 2..i + 2 + p];
                    if let Ok(num) = name.parse::<usize>() {
                        if let Some(m) = caps.get(num) {
                            out.extend_from_slice(m.as_bytes());
                        }
                    } else if !name.is_empty() {
                        if let Some(m) = caps.name(name) {
                            out.extend_from_slice(m.as_bytes());
                        }
                    }
                    i = i + 2 + p + 1;
                    continue;
                } else {
                    out.push(b'$');
                    i += 1;
                    continue;
                }
            }
            let mut j = i + 1;
            while j < n && bytes[j].is_ascii_digit() {
                j += 1;
            }
            if j > i + 1 {
                let num: usize = replacement[i + 1..j].parse().unwrap_or(0);
                if let Some(m) = caps.get(num) {
                    out.extend_from_slice(m.as_bytes());
                }
                i = j;
            } else {
                let mut j = i + 1;
                while j < n && is_word(bytes[j]) {
                    j += 1;
                }
                if j > i + 1 {
                    let name = &replacement[i + 1..j];
                    if let Some(m) = caps.name(name) {
                        out.extend_from_slice(m.as_bytes());
                    }
                    i = j;
                } else {
                    out.push(b'$');
                    i += 1;
                }
            }
        } else {
            out.push(b);
            i += 1;
        }
    }
    out
}

pub fn build_regex(
    find: &str,
    flags: Option<&str>,
    fixed_strings: bool,
) -> Result<Regex, String> {
    let fs: FlagSet = parse_flags(flags);

    let pattern = if fixed_strings {
        regex::escape(find)
    } else {
        find.to_string()
    };

    let pattern = if fs.word_bounded {
        format!(r"\b(?:{})\b", pattern)
    } else {
        pattern
    };

    let mut builder = RegexBuilder::new(&pattern);
    builder.multi_line(fs.multi_line);
    builder.case_insensitive(fs.case_insensitive);
    builder.dot_matches_new_line(fs.dot_all);
    builder.unicode(true);
    builder.build().map_err(|e| {
        // Match reference error format: "invalid regex regex parse error:\n    ..."
        format!("invalid regex {}", e)
    })
}

pub fn replace_all(
    re: &Regex,
    haystack: &[u8],
    replacement: &str,
    fixed_strings: bool,
    max_replacements: u64,
) -> Vec<u8> {
    let mut out = Vec::with_capacity(haystack.len());
    let mut last_end = 0;
    let mut count: u64 = 0;
    let unlimited = max_replacements == 0;
    let repl_bytes = if fixed_strings {
        Some(replacement.as_bytes().to_vec())
    } else {
        None
    };

    for caps in re.captures_iter(haystack) {
        if !unlimited && count >= max_replacements {
            break;
        }
        let m = caps.get(0).unwrap();
        out.extend_from_slice(&haystack[last_end..m.start()]);
        if let Some(rb) = &repl_bytes {
            out.extend_from_slice(rb);
        } else {
            let expanded = expand(replacement, &caps);
            out.extend_from_slice(&expanded);
        }
        last_end = m.end();
        count += 1;
        // Handle empty match: regex crate captures_iter handles this OK, but make sure
    }
    out.extend_from_slice(&haystack[last_end..]);
    out
}

