    let unlimited = max_replacements == 0;
    let repl_bytes = if fixed_strings {
        Some(replacement.as_bytes().to_vec())
    } else {
        None
    };

    for caps in re.captures_iter(haystack) {
        if !unlimited && count >= max_replacements {
            break;
        }
        let m = caps.get(0).unwrap();
        out.extend_from_slice(&haystack[last_end..m.start()]);
        if let Some(rb) = &repl_bytes {
            out.extend_from_slice(rb);
        } else {
            let expanded = expand(replacement, &caps);
            out.extend_from_slice(&expanded);
        }
        last_end = m.end();
        count += 1;
        // Handle empty match: regex crate captures_iter handles this OK, but make sure
    }
    out.extend_from_slice(&haystack[last_end..]);
    out
}

use std::io::{Read, Write};
use std::path::PathBuf;

use crate::replacer;

pub struct Options {
    pub preview: bool,
    pub fixed_strings: bool,
    pub max_replacements: u64,
    pub flags: Option<String>,
    pub find: String,
    pub replace_with: String,
    pub files: Vec<PathBuf>,
}

pub fn run(opts: Options) -> Result<(), u8> {
    // 1. Ambiguity check (regex mode only)
    if !opts.fixed_strings {
        if let Err(amb) = replacer::check_ambiguous(&opts.replace_with) {
            eprint!("{}", amb.render());
            return Err(1);
        }
    }

    // 2. Build the regex
    let re = match replacer::build_regex(&opts.find, opts.flags.as_deref(), opts.fixed_strings) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("error: {}", e);
            return Err(1);
        }
    };

    if opts.files.is_empty() {
        // stdin -> stdout
        let mut buf = Vec::new();
        if std::io::stdin().lock().read_to_end(&mut buf).is_err() {
            return Err(1);
        }
        let out = replacer::replace_all(
            &re,
            &buf,
            &opts.replace_with,
            opts.fixed_strings,
            opts.max_replacements,
        );
        let _ = std::io::stdout().lock().write_all(&out);
        return Ok(());
    }

    // Validate all paths first
    for path in &opts.files {
        if !path.is_file() {
            // try follow symlinks via metadata
            match std::fs::metadata(path) {
                Ok(m) if m.is_file() => {}
                _ => {
                    eprintln!("error: invalid path: {}", path.display());
                    return Err(1);
                }
            }
        }
    }

    // Process files
    let multi = opts.files.len() > 1;
    for path in &opts.files {
        let buf = match std::fs::read(path) {
            Ok(b) => b,
            Err(e) => {
                eprintln!("error: {}", e);
                return Err(1);
            }
        };
        let out = replacer::replace_all(
            &re,
            &buf,
            &opts.replace_with,
            opts.fixed_strings,
            opts.max_replacements,
        );

        if opts.preview {
            let stdout = std::io::stdout();
            let mut h = stdout.lock();
            if multi {
                let _ = write!(h, "----- FILE {} -----\n", path.display());
            }
            let _ = h.write_all(&out);
        } else {
            // Write back to file
            if let Err(e) = write_file(path, &out) {
                eprintln!("error: {}", e);
                return Err(1);
            }
        }
    }
    Ok(())
}

fn write_file(path: &std::path::Path, content: &[u8]) -> std::io::Result<()> {
    let parent = path.parent().unwrap_or_else(|| std::path::Path::new("."));
    let mut tmp = tempfile::NamedTempFile::new_in(parent)?;
    tmp.write_all(content)?;
    tmp.persist(path).map_err(|e| e.error)?;
    Ok(())
}

