#!/bin/bash
# Compare goldens against my reimplementation
set -u

GOLDENS_DIR=${1:-/work/work/goldens}
SUT=${SUT:-/work/work/executable}
TMPDIR=$(mktemp -d)
trap "rm -rf $TMPDIR" EXIT

PASS=0
FAIL=0
FAILED_NAMES=()

# Re-run the same probes but against SUT instead of REF
# Probe definitions need to be re-derived from capture_goldens.sh

probe_args() {
    local name="$1"
    case "$name" in
        # Surface scan
        "help-long") ARGS=("--help"); STDIN="" ;;
        "help-short") ARGS=("-h"); STDIN="" ;;
        "version-long") ARGS=("--version"); STDIN="" ;;
        "version-short") ARGS=("-V"); STDIN="" ;;
        "empty-args") ARGS=(); STDIN="" ;;
        "bogus-flag") ARGS=("--bogus"); STDIN="" ;;
        "dash") ARGS=("-"); STDIN="" ;;
        "doubledash") ARGS=("--"); STDIN="" ;;
        "single-find") ARGS=("foo"); STDIN="" ;;
        # Basic replace
        "basic-replace") ARGS=("hello" "goodbye"); STDIN="hello world" ;;
        "regex-digits") ARGS=('\d+' "NUM"); STDIN="hello world 123" ;;
        "no-match") ARGS=("xyz" "QQQ"); STDIN="abc" ;;
        "empty-stdin") ARGS=("hello" "goodbye"); STDIN="" ;;
        "empty-find") ARGS=("" "X"); STDIN="abc" ;;
        "empty-replace") ARGS=("a" ""); STDIN="abc" ;;
        "both-empty") ARGS=("" ""); STDIN="abc" ;;
        # Capture groups
        "capgroup-numbered") ARGS=('(\w+)\s+\+(\w+)\s+(\w+)' 'cmd: $1, channel: $2, subcmd: $3'); STDIN="cargo +nightly watch" ;;
        "capgroup-named") ARGS=('(?P<dollars>\d+)\.(?P<cents>\d+)' '$dollars dollars and $cents cents'); STDIN="123.45" ;;
        "capgroup-braces") ARGS=('(?P<dollars>\d+)\.(?P<cents>\d+)' '${dollars}_dollars and ${cents}_cents'); STDIN="123.45" ;;
        "capgroup-unclosed") ARGS=('(?P<dollars>\d+)\.(?P<cents>\d+)' '$dollars_dollars and $cents_cents'); STDIN="123.45" ;;
        "dollar-dollar") ARGS=("foo" '$$bar'); STDIN="foo" ;;
        "dollar-1-end") ARGS=("a" '$1'); STDIN="abc" ;;
        # Ambiguity
        "ambig-1y") ARGS=("a" 'X$1Y'); STDIN="abc" ;;
        "ambig-2-existing") ARGS=("(a)" 'X$2Y'); STDIN="abc" ;;
        "ambig-0") ARGS=("b" 'X$0Y'); STDIN="abc" ;;
        "ambig-10y") ARGS=("a" 'X$10Y'); STDIN="abc" ;;
        "ambig-underscore") ARGS=("a" '$1_'); STDIN="abc" ;;
        "ambig-comma") ARGS=("a" '$1,'); STDIN="abc" ;;
        "ambig-dash") ARGS=("a" '$1-'); STDIN="abc" ;;
        "ambig-named-no-group") ARGS=("a" 'X${name}Y'); STDIN="abc" ;;
        # Fixed-strings
        "fixed-special-chars") ARGS=("-F" '((([])))' ''); STDIN='lots((([]))) of special chars' ;;
        "fixed-long") ARGS=("--fixed-strings" '((([])))' ''); STDIN='lots((([]))) of special chars' ;;
        "fixed-dollar") ARGS=("-F" "foo" '$$bar'); STDIN='foo' ;;
        "fixed-newline") ARGS=("-F" "foo" 'a\nb'); STDIN=$'foo\n' ;;
        # Escape interpretation in regex mode
        "regex-newline-in-replace") ARGS=("foo" 'a\nb'); STDIN=$'foo\n' ;;
        "regex-tab-in-replace") ARGS=("foo" 'a\tb'); STDIN="foo" ;;
        # Flags
        "flag-i") ARGS=("-f" "i" "hello" "goodbye"); STDIN="Hello WORLD" ;;
        "flag-w") ARGS=("-f" "w" "hello" "X"); STDIN="hello hello1 hello" ;;
        "flag-m-anchored") ARGS=("-f" "m" '^abc$' "X"); STDIN=$'abc\nabc' ;;
        "flag-s-dot") ARGS=("-f" "s" "a.b" "X"); STDIN=$'a\nb' ;;
        "flag-default-multiline") ARGS=('^abc$' "X"); STDIN=$'abc\nabc' ;;
        "flag-e-disables") ARGS=("-f" "e" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-s-disables-m") ARGS=("-f" "s" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-w-disables-m") ARGS=("-f" "w" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-sm-keeps-m") ARGS=("-f" "sm" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-wm-stays-off") ARGS=("-f" "wm" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-em-off") ARGS=("-f" "em" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-me-off") ARGS=("-f" "me" '^abc' "X"); STDIN=$'abc\nabc' ;;
        "flag-ci-last-i") ARGS=("-f" "ci" "hello" "X"); STDIN="Hello" ;;
        "flag-ic-last-c") ARGS=("-f" "ic" "hello" "X"); STDIN="Hello" ;;
        "flag-icic") ARGS=("-f" "icic" "hello" "X"); STDIN="Hello" ;;
        "flag-cici") ARGS=("-f" "cici" "hello" "X"); STDIN="Hello" ;;
        "flag-empty") ARGS=("-f" "" "hello" "X"); STDIN="Hello" ;;
        "flag-unknown") ARGS=("-f" "q" "test" "X"); STDIN="test" ;;
        "flag-digit") ARGS=("-f" "1" "test" "X"); STDIN="test" ;;
        "flag-w-no-boundary") ARGS=("-f" "w" "1" "X"); STDIN="a1b" ;;
        "flag-w-with-boundary") ARGS=("-f" "w" "b" "X"); STDIN="a-b" ;;
        # Max replacements
        "n-1") ARGS=("-n" "1" "a" "X"); STDIN="aaaa" ;;
        "n-0") ARGS=("-n" "0" "a" "X"); STDIN="aaaa" ;;
        "n-2") ARGS=("-n" "2" "a" "X"); STDIN="aaaa" ;;
        "n-big") ARGS=("-n" "100" "a" "X"); STDIN="aaaa" ;;
        "n-eq") ARGS=("-n=2" "a" "X"); STDIN="aaaa" ;;
        "n-attached") ARGS=("-n2" "a" "X"); STDIN="aaaa" ;;
        "n-neg") ARGS=("--max-replacements=-1" "a" "X"); STDIN="aaaa" ;;
        "n-non-number") ARGS=("-n" "abc" "a" "X"); STDIN="aaaa" ;;
        "n-overflow") ARGS=("-n" "99999999999999999999" "a" "X"); STDIN="aaaa" ;;
        # Preview / stdin
        "preview-stdin") ARGS=("-p" "h" "X"); STDIN="hello" ;;
        "preview-no-match") ARGS=("-p" "xxx" "X"); STDIN="abc" ;;
        # Args parsing
        "F-twice") ARGS=("-F" "-F" "a" "X"); STDIN="abc" ;;
        "p-twice") ARGS=("-p" "-p" "a" "X"); STDIN="abc" ;;
        "f-twice") ARGS=("-f" "i" "-f" "m" "a" "X"); STDIN="abc" ;;
        "n-twice") ARGS=("-n" "1" "-n" "2" "a" "X"); STDIN="abc" ;;
        # Regex syntax errors
        "regex-unclosed") ARGS=("[" "X"); STDIN="abc" ;;
        "regex-look-ahead") ARGS=("(?=abc)" "X"); STDIN="abc" ;;
        "regex-look-behind") ARGS=("(?<=abc)" "X"); STDIN="abc" ;;
        "regex-unclosed-paren") ARGS=("(abc" "X"); STDIN="abc" ;;
        "regex-empty-named") ARGS=("(?P<>abc)" "X"); STDIN="abc" ;;
        "regex-unknown-flag") ARGS=("(?z)abc" "X"); STDIN="abc" ;;
        # Binary/UTF8
        "stdin-binary") ARGS=("b" "X"); STDIN=$'a\x00b\x01c' ;;
        "stdin-invalid-utf8") ARGS=("b" "X"); STDIN=$'a\xffb' ;;
        "stdin-bom") ARGS=("hello" "X"); STDIN=$'\xef\xbb\xbfhello' ;;
        "stdin-crlf") ARGS=("b" "X"); STDIN=$'a\r\nb' ;;
        "utf8-chars") ARGS=("a" "X"); STDIN="naïve café" ;;
        "utf8-match-pattern") ARGS=("café" "X"); STDIN="naïve café" ;;
        # Empty/edge cases
        "empty-find-regex") ARGS=("" "X"); STDIN="abc" ;;
        "empty-find-fixed") ARGS=("-F" "" "X"); STDIN="abc" ;;
        # Replacement edge cases
        "ambig-1-no-trail-eof") ARGS=("a" '$1'); STDIN="abc" ;;
        "ambig-1-space-after") ARGS=("a" '$1 Y'); STDIN="abc" ;;
        "ambig-1-bang-after") ARGS=("a" '$1!Y'); STDIN="abc" ;;
        "ambig-1-digit-after") ARGS=("a" '$11'); STDIN="abc" ;;
        # Inline flag override
        "inline-m-override-e") ARGS=("-f" "e" '(?m)^abc' "X"); STDIN=$'abc\nabc' ;;
        "inline-m-override-s") ARGS=("-f" "s" '(?m)^abc' "X"); STDIN=$'abc\nabc' ;;
        "inline-m-override-w") ARGS=("-f" "w" '(?m)^abc' "X"); STDIN=$'abc\nabc' ;;
        *) return 1 ;;
    esac
    return 0
}

for ec_file in "$GOLDENS_DIR"/*.ec; do
    name=$(basename "$ec_file" .ec)
    expected_ec=$(<"$ec_file")
    expected_stdout="$GOLDENS_DIR/$name.stdout"
    expected_stderr="$GOLDENS_DIR/$name.stderr"

    if ! probe_args "$name"; then
        echo "SKIP: $name (no probe definition)"
        continue
    fi
    actual_stdout=$(mktemp)
    actual_stderr=$(mktemp)
    if [ -n "$STDIN" ]; then
        printf '%s' "$STDIN" | timeout 10 "$SUT" "${ARGS[@]}" >"$actual_stdout" 2>"$actual_stderr"
    else
        : | timeout 10 "$SUT" "${ARGS[@]}" >"$actual_stdout" 2>"$actual_stderr"
    fi
    actual_ec=$?

    ok=true
    if [ "$actual_ec" != "$expected_ec" ]; then ok=false; fi
    if ! diff -q "$actual_stdout" "$expected_stdout" >/dev/null 2>&1; then ok=false; fi
    if ! diff -q "$actual_stderr" "$expected_stderr" >/dev/null 2>&1; then ok=false; fi

    if $ok; then
        PASS=$((PASS+1))
    else
        FAIL=$((FAIL+1))
        FAILED_NAMES+=("$name")
        if [ "${VERBOSE:-0}" = "1" ]; then
            echo "FAIL: $name"
            echo "  Expected EC: $expected_ec  Actual: $actual_ec"
            echo "  stdout diff:"
            diff "$expected_stdout" "$actual_stdout" | head -20 | sed 's/^/    /'
            echo "  stderr diff:"
            diff "$expected_stderr" "$actual_stderr" | head -20 | sed 's/^/    /'
        fi
    fi

    rm -f "$actual_stdout" "$actual_stderr"
done

echo "=== Pass: $PASS  Fail: $FAIL ==="
if [ $FAIL -gt 0 ]; then
    echo "Failed: ${FAILED_NAMES[@]}"
fi

